            assert_eq!(active_tool_session_id().as_deref(), Some("outer"));

            with_active_tool_session(Some("inner"), || {
                assert_eq!(active_tool_session_id().as_deref(), Some("inner"));
            });

            assert_eq!(active_tool_session_id().as_deref(), Some("outer"));
        });

        assert_eq!(active_tool_session_id(), None);
    }

