            }
        }
    }

    pub fn remove(&self, task_id: &str) -> Option<Task> {
        let mut inner = self
            .state
            .inner
            .lock()
            .unwrap_or_else(std::sync::PoisonError::into_inner);
        let removed = inner.tasks.remove(task_id);
        if removed.is_some() {
            self.state.changed.notify_all();
