        "+#![allow(clippy::must_use_candidate, clippy::unnecessary_map_or)]",
        "+//! In-memory task registry for sub-agent task lifecycle management.",
        "+",
        "+use std::collections::HashMap;",
        "+use std::sync::{Arc, Condvar, Mutex};",
        "+use std::time::Duration;",
        "+use std::time::{SystemTime, UNIX_EPOCH};",
        "+",
        "+use serde::{Deserialize, Serialize};",
        "+",
        "+use crate::{validate_packet, TaskPacket, TaskPacketValidationError};",
        "+",
        "+#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]",
        "+#[serde(rename_all = "snake_case")]",
        "+pub enum TaskStatus {",
        "+    Created,",
        "+    Running,",
        "+    Completed,",
        "+    Failed,",
        "+    Stopped,",
        "+}",
        "+",
        "+impl std::fmt::Display for TaskStatus {",
        "+    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {",
        "+        match self {",
        "+            Self::Created => write!(f, "created"),",
        "+            Self::Running => write!(f, "running"),",
        "+            Self::Completed => write!(f, "completed"),",
        "+            Self::Failed => write!(f, "failed"),",
        "+            Self::Stopped => write!(f, "stopped"),",
        "+        }",
        "+    }",
        "+}",
        "+",
        "+#[derive(Debug, Clone, Serialize, Deserialize)]",
        "+pub struct Task {",
        "+    pub task_id: String,",
        "+    pub prompt: String,",
        "+    pub description: Option<String>,",
        "+    pub task_packet: Option<TaskPacket>,",
        "+    pub status: TaskStatus,",
        "+    pub created_at: u64,",
        "+    pub updated_at: u64,",
        "+    pub messages: Vec<TaskMessage>,",
        "+    pub output: String,",
        "+    pub team_id: Option<String>,",
        "+}",
        "+",
        "+#[derive(Debug, Clone, Serialize, Deserialize)]",
        "+pub struct TaskMessage {",
        "+    pub role: String,",
        "+    pub content: String,",
        "+    pub timestamp: u64,",
        "+}",
        "+",
        "+#[derive(Debug, Clone, Default)]",
        "+pub struct TaskRegistry {",
        "+    state: Arc<RegistryState>,",
        "+}",
        "+",
        "+#[derive(Debug, Default)]",
        "+struct RegistryState {",
        "+    inner: Mutex<RegistryInner>,",
        "+    changed: Condvar,",
        "+}",
        "+",
        "+#[derive(Debug, Default)]",
        "+struct RegistryInner {",
        "+    tasks: HashMap<String, Task>,",
        "+    counter: u64,",
        "+}",
        "+",
        "+fn now_secs() -> u64 {",
        "+    SystemTime::now()",
        "+        .duration_since(UNIX_EPOCH)",
        "+        .unwrap_or_default()",
        "+        .as_secs()",
        "+}",
        "+",
        "+impl TaskRegistry {",
        "+    #[must_use]",
        "+    pub fn new() -> Self {",
        "+        Self::default()",
        "+    }",
        "+",
        "+    pub fn create(&self, prompt: &str, description: Option<&str>) -> Task {",
        "+        self.create_task(prompt.to_owned(), description.map(str::to_owned), None)",
        "+    }",
        "+",
        "+    /// Create a task with a caller-supplied ID (e.g. an agent ID) so that",
        "+    /// external subsystems can look it up by the same identifier.",
        "+    pub fn create_with_id(&self, task_id: String, prompt: &str, description: Option<&str>) -> Task {",
        "+        self.insert_task(",
        "+            task_id,",
        "+            prompt.to_owned(),",
        "+            description.map(str::to_owned),",
        "+            None,",
        "+        )",
        "+    }",
        "+",
        "+    pub fn create_from_packet(",
        "+        &self,",
        "+        packet: TaskPacket,",
        "+    ) -> Result<Task, TaskPacketValidationError> {",
        "+        let packet = validate_packet(packet)?.into_inner();",
        "+        Ok(self.create_task(",
        "+            packet.objective.clone(),",
        "+            Some(packet.scope.clone()),",
        "+            Some(packet),",
        "+        ))",
        "+    }",
        "+",
        "+    fn create_task(",
        "+        &self,",
        "+        prompt: String,",
        "+        description: Option<String>,",
        "+        task_packet: Option<TaskPacket>,",
        "+    ) -> Task {",
        "+        let task_id = {",
        "+            let mut inner = self",
        "+                .state",
        "+                .inner",
        "+                .lock()",
        "+                .unwrap_or_else(std::sync::PoisonError::into_inner);",
        "+            inner.counter += 1;",
        "+            let ts = now_secs();",
        "+            format!("task_{:08x}_{}", ts, inner.counter)",
        "+        };",
        "+        self.insert_task(task_id, prompt, description, task_packet)",
        "+    }",
        "+",
        "+    fn insert_task(",
        "+        &self,",
        "+        task_id: String,",
        "+        prompt: String,",
        "+        description: Option<String>,",
        "+        task_packet: Option<TaskPacket>,",
        "+    ) -> Task {",
        "+        let mut inner = self",
        "+            .state",
        "+            .inner",
        "+            .lock()",
        "+            .unwrap_or_else(std::sync::PoisonError::into_inner);",
        "+        let ts = now_secs();",
        "+        let task = Task {",
        "+            task_id: task_id.clone(),",
        "+            prompt,",
        "+            description,",
        "+            task_packet,",
        "+            status: TaskStatus::Created,",
        "+            created_at: ts,",
        "+            updated_at: ts,",
        "+            messages: Vec::new(),",
        "+            output: String::new(),",
        "+            team_id: None,",
        "+        };",
        "+        inner.tasks.insert(task_id, task.clone());",
        "+        task",
        "+    }",
        "+",
        "+    pub fn get(&self, task_id: &str) -> Option<Task> {",
        "+        let inner = self",
        "+            .state",
        "+            .inner",
        "+            .lock()",
        "+            .unwrap_or_else(std::sync::PoisonError::into_inner);",
        "+        inner.tasks.get(task_id).cloned()",
        "+    }",
        "+",
        "+    pub fn list(&self, status_filter: Option<TaskStatus>) -> Vec<Task> {",
        "+        let inner = self",
        "+            .state",
        "+            .inner",
        "+            .lock()",
        "+            .unwrap_or_else(std::sync::PoisonError::into_inner);",
        "+        inner",
        "+            .tasks",
        "+            .values()",
        "+            .filter(|t| status_filter.map_or(true, |s| t.status == s))",
        "+            .cloned()",
        "+            .collect()",
        "+    }",
        "+",
        "+    pub fn stop(&self, task_id: &str) -> Result<Task, String> {",
        "+        let mut inner = self",
        "+            .state",
        "+            .inner",
        "+            .lock()",
        "+            .unwrap_or_else(std::sync::PoisonError::into_inner);",
        "+        let task = inner",
        "+            .tasks",
        "+            .get_mut(task_id)",
        "+            .ok_or_else(|| format!("task not found: {task_id}"))?;",
        "+",
        "+        match task.status {",
        "+            TaskStatus::Completed | TaskStatus::Failed | TaskStatus::Stopped => {",
        "+                return Err(format!(",
        "+                    "task {task_id} is already in terminal state: {}",",
        "+                    task.status",
        "+                ));",
        "+            }",
        "+            _ => {}",
        "+        }",
        "+",
        "+        task.status = TaskStatus::Stopped;",
        "+        task.updated_at = now_secs();",
        "+        self.state.changed.notify_all();",
        "+        Ok(task.clone())",
        "+    }",
        "+",
        "+    pub fn update(&self, task_id: &str, message: &str) -> Result<Task, String> {",
        "+        let mut inner = self",
        "+            .state",
        "+            .inner",
        "+            .lock()",
        "+            .unwrap_or_else(std::sync::PoisonError::into_inner);",
        "+        let task = inner",
        "+            .tasks",
        "+            .get_mut(task_id)",
        "+            .ok_or_else(|| format!("task not found: {task_id}"))?;",
        "+",
        "+        task.messages.push(TaskMessage {",
        "+            role: String::from("user"),",
        "+            content: message.to_owned(),",
        "+            timestamp: now_secs(),",
        "+        });",
        "+        task.updated_at = now_secs();",
        "+        Ok(task.clone())",
        "+    }",
        "+",
        "+    pub fn output(&self, task_id: &str) -> Result<String, String> {",
        "+        let inner = self",
        "+            .state",
        "+            .inner",
        "+            .lock()",
        "+            .unwrap_or_else(std::sync::PoisonError::into_inner);",
        "+        let task = inner",
        "+            .tasks",
        "+            .get(task_id)",
        "+            .ok_or_else(|| format!("task not found: {task_id}"))?;",
        "+        Ok(task.output.clone())",
        "+    }",
        "+",
        "+    pub fn append_output(&self, task_id: &str, output: &str) -> Result<(), String> {",
        "+        let mut inner = self",
        "+            .state",
        "+            .inner",
        "+            .lock()",
        "+            .unwrap_or_else(std::sync::PoisonError::into_inner);",
        "+        let task = inner",
        "+            .tasks",
        "+            .get_mut(task_id)",
        "+            .ok_or_else(|| format!("task not found: {task_id}"))?;",
        "+        task.output.push_str(output);",
        "+        task.updated_at = now_secs();",
        "+        Ok(())",
        "+    }",
        "+",
        "+    pub fn set_status(&self, task_id: &str, status: TaskStatus) -> Result<(), String> {",
        "+        let mut inner = self",
        "+            .state",
        "+            .inner",
        "+            .lock()",
        "+            .unwrap_or_else(std::sync::PoisonError::into_inner);",
        "+        let task = inner",
        "+            .tasks",
        "+            .get_mut(task_id)",
        "+            .ok_or_else(|| format!("task not found: {task_id}"))?;",
        "+        task.status = status;",
        "+        task.updated_at = now_secs();",
        "+        self.state.changed.notify_all();",
        "+        Ok(())",
        "+    }",
        "+",
        "+    pub fn assign_team(&self, task_id: &str, team_id: &str) -> Result<(), String> {",
        "+        let mut inner = self",
        "+            .state",
        "+            .inner",
        "+            .lock()",
        "+            .unwrap_or_else(std::sync::PoisonError::into_inner);",
        "+        let task = inner",
        "+            .tasks",
        "+            .get_mut(task_id)",
        "+            .ok_or_else(|| format!("task not found: {task_id}"))?;",
        "+        task.team_id = Some(team_id.to_owned());",
        "+        task.updated_at = now_secs();",
        "+        Ok(())",
        "+    }",
        "+",
        "+    pub fn wait_for_terminal(&self, task_id: &str, timeout: Duration) -> Result<Task, String> {",
        "+        let mut inner = self",
        "+            .state",
        "+            .inner",
        "+            .lock()",
        "+            .unwrap_or_else(std::sync::PoisonError::into_inner);",
        "+        let start = std::time::Instant::now();",
        "+",
        "+        loop {",
        "+            let task = inner",
        "+                .tasks",
        "+                .get(task_id)",
        "+                .cloned()",
        "+                .ok_or_else(|| format!("task not found: {task_id}"))?;",
        "+",
        "+            if !matches!(task.status, TaskStatus::Created | TaskStatus::Running) {",
        "+                return Ok(task);",
        "+            }",
        "+",
        "+            let Some(remaining) = timeout.checked_sub(start.elapsed()) else {",
        "+                return Ok(task);",
        "+            };",
        "+            if remaining.is_zero() {",
        "+                return Ok(task);",
        "+            }",
        "+",
        "+            let (next_inner, wait_result) = self",
        "+                .state",
        "+                .changed",
        "+                .wait_timeout(inner, remaining)",
        "+                .unwrap_or_else(std::sync::PoisonError::into_inner);",
        "+            inner = next_inner;",
        "+            if wait_result.timed_out() {",
        "+                let task = inner",
        "+                    .tasks",
