        "-        "McpAuth" => from_value::<McpAuthInput>(input).and_then(run_mcp_auth),",
        "-        "RemoteTrigger" => from_value::<RemoteTriggerInput>(input).and_then(run_remote_trigger),",
        "-        "MCP" => from_value::<McpToolInput>(input).and_then(run_mcp_tool),",
