        "-fn maybe_enforce_permission_check(",
        "-    enforcer: Option<&PermissionEnforcer>,",
        "-    tool_name: &str,",
        "-    input: &Value,",
        "-) -> Result<(), String> {",
        "-    if let Some(enforcer) = enforcer {",
        "-        enforce_permission_check(enforcer, tool_name, input)?;",
        "-    }",
        "-    Ok(())",
        "-}",
