        "-fn is_workspace_test_command(command: &str) -> bool {",
        "-    let normalized = normalize_shell_command(command);",
        "-    [",
        "-        "cargo test --workspace",",
        "-        "cargo test --all",",
        "-        "cargo nextest run --workspace",",
        "-        "cargo nextest run --all",",
        "-    ]",
        "-    .iter()",
        "-    .any(|needle| normalized.contains(needle))",
