        "-        .unwrap_or_else(|| trimmed.to_string());",
        "-    candidate",
        "-        .trim()",
        "-        .trim_start_matches('.')",
        "-        .trim_end_matches('/')",
        "-        .to_ascii_lowercase()",
        "-}",
