        "-",
        "-fn spawn_agent_job(job: AgentJob) -> Result<(), String> {",
        "-    let started_at = Instant::now();",
        "-    let spawned_agent_id = job.manifest.agent_id.clone();",
        "-    agent_debug_log(",
        "-        "agent.background.register.begin",",
