        "-            let started_at = Instant::now();",
        "-            let result =",
        "-                std::panic::catch_unwind(std::panic::AssertUnwindSafe(|| run_agent_job(&job)));",
        "-            match result {",
        "-                Ok(Ok(())) => {",
        "-                    agent_debug_log(",
        "-                        "agent.background.thread.completed",",
        "-                        format!(",
        "-                            "agent_id={} elapsed_ms={}",",
        "-                            job.manifest.agent_id,",
        "-                            started_at.elapsed().as_millis()",
