        "-        })",
        "-}",
        "-",
        "-fn enqueue_background_agent_notification(job: &AgentJob, status: &str, body: &str) {",
        "-    let Some(session_id) = job.parent_session_id.as_deref() else {",
        "-        return;",
        "-    };",
