        "-    if normalized_error.contains("transport")",
        "-        || normalized_error.contains("broken pipe")",
        "-        || normalized_error.contains("connection")",
        "-        || normalized_error.contains("interrupted")",
        "-    {",
        "-        return "interrupted_transport";",
        "-    }",
        "-    if blocker.is_some() {",
