        "-    let mut stream = client.stream_message(message_request).await?;",
        "-    let mut events = Vec::new();",
        "-    let mut pending_tools: BTreeMap<u32, (String, String, String)> = BTreeMap::new();",
        "-    let mut saw_stop = false;",
