        "-fn normalize_tool_search_query(query: &str) -> String {",
        "-    query",
        "-        .trim()",
        "-        .split(|ch: char| ch.is_whitespace() || ch == ',')",
        "-        .filter(|term| !term.is_empty())",
        "-        .map(canonical_tool_token)",
        "-        .collect::<Vec<_>>()",
