        "-    let cwd = std::env::current_dir().map_err(|error| error.to_string())?;",
        "-    Ok(match scope {",
        "-        ConfigScope::Global => config_home_dir()?.join("settings.json"),",
        "-        ConfigScope::Settings => cwd.join(".claw").join("settings.local.json"),",
        "-    })",
