        "+            "ToolSearch",",
        "+            "Skill",",
        "+            "TodoWrite",",
        "+            "StructuredOutput",",
        "+            "SendUserMessage",",
        "+        ],",
        "+        "Verification" => vec![",
        "+            "bash",",
        "+            "read_file",",
        "+            "glob_search",",
        "+            "grep_search",",
        "+            "WebFetch",",
        "+            "WebSearch",",
        "+            "ToolSearch",",
        "+            "TodoWrite",",
        "+            "StructuredOutput",",
        "+            "SendUserMessage",",
        "+            "PowerShell",",
        "+        ],",
        "+        "claw-guide" => vec![",
        "+            "read_file",",
        "+            "glob_search",",
        "+            "grep_search",",
        "+            "WebFetch",",
        "+            "WebSearch",",
        "+            "ToolSearch",",
        "+            "Skill",",
        "+            "StructuredOutput",",
        "+            "SendUserMessage",",
        "+        ],",
        "+        "statusline-setup" => vec![",
        "+            "bash",",
        "+            "read_file",",
        "+            "write_file",",
        "+            "edit_file",",
        "+            "glob_search",",
        "+            "grep_search",",
        "+            "ToolSearch",",
        "+        ],",
        "+        _ => vec![",
        "+            "bash",",
        "+            "read_file",",
        "+            "write_file",",
        "+            "edit_file",",
        "+            "glob_search",",
        "+            "grep_search",",
        "+            "WebFetch",",
        "+            "WebSearch",",
        "+            "TodoWrite",",
        "+            "Skill",",
        "+            "ToolSearch",",
        "+            "NotebookEdit",",
        "+            "Sleep",",
        "+            "SendUserMessage",",
