        "+impl ApiClient for ProviderRuntimeClient {",
        "+    fn stream(&mut self, request: ApiRequest) -> Result<Vec<AssistantEvent>, RuntimeError> {",
        "+        let tools = tool_specs_for_allowed_tools(Some(&self.allowed_tools))",
        "+            .into_iter()",
        "+            .map(|spec| ToolDefinition {",
        "+                name: spec.name.to_string(),",
        "+                description: Some(spec.description.to_string()),",
        "+                input_schema: spec.input_schema,",
        "+            })",
        "+            .collect::<Vec<_>>();",
        "+        let messages = convert_messages(&request.messages);",
        "+        let system =",
        "+            (!request.system_prompt.is_empty()).then(|| request.system_prompt.join("\n\n"));",
        "+        let tool_choice = (!self.allowed_tools.is_empty()).then_some(ToolChoice::Auto);",
        "+",
        "+        let runtime = &self.runtime;",
        "+        let chain = &self.chain;",
        "+        let mut last_error: Option<ApiError> = None;",
        "+        for (index, entry) in chain.iter().enumerate() {",
        "+            let attempt_started_at = Instant::now();",
        "+            agent_debug_log(",
        "+                "agent.provider.stream.begin",",
        "+                format!(",
        "+                    "model={} attempt={} chain_len={} messages={} tools={} system_prompt_parts={}",",
        "+                    entry.model,",
        "+                    index + 1,",
        "+                    chain.len(),",
        "+                    request.messages.len(),",
        "+                    tools.len(),",
        "+                    request.system_prompt.len()",
        "+                ),",
        "+            );",
        "+            let message_request = MessageRequest {",
        "+                model: entry.model.clone(),",
        "+                max_tokens: max_tokens_for_model(&entry.model),",
        "+                messages: messages.clone(),",
        "+                system: system.clone(),",
        "+                tools: (!tools.is_empty()).then(|| tools.clone()),",
        "+                tool_choice: tool_choice.clone(),",
        "+                stream: true,",
        "+                ..Default::default()",
        "+            };",
        "+",
        "+            let attempt = runtime.block_on(stream_with_provider(&entry.client, &message_request));",
        "+            match attempt {",
        "+                Ok(events) => {",
        "+                    agent_debug_log(",
        "+                        "agent.provider.stream.success",",
        "+                        format!(",
        "+                            "model={} attempt={} elapsed_ms={} events={}",",
        "+                            entry.model,",
        "+                            index + 1,",
        "+                            attempt_started_at.elapsed().as_millis(),",
        "+                            events.len()",
        "+                        ),",
        "+                    );",
        "+                    return Ok(events);",
        "+                }",
        "+                Err(error) if error.is_retryable() && index + 1 < chain.len() => {",
        "+                    agent_debug_log(",
        "+                        "agent.provider.stream.retryable_error",",
        "+                        format!(",
        "+                            "model={} attempt={} elapsed_ms={} error={error}",",
        "+                            entry.model,",
        "+                            index + 1,",
        "+                            attempt_started_at.elapsed().as_millis()",
        "+                        ),",
        "+                    );",
        "+                    eprintln!(",
        "+                        "provider {} failed with retryable error, falling back: {error}",",
        "+                        entry.model",
        "+                    );",
        "+                    last_error = Some(error);",
        "+                    continue;",
        "+                }",
        "+                Err(error) => {",
        "+                    agent_debug_log(",
        "+                        "agent.provider.stream.error",",
        "+                        format!(",
        "+                            "model={} attempt={} elapsed_ms={} error={error}",",
        "+                            entry.model,",
        "+                            index + 1,",
        "+                            attempt_started_at.elapsed().as_millis()",
        "+                        ),",
        "+                    );",
        "+                    return Err(RuntimeError::new(error.to_string()));",
        "+                }",
        "+            }",
        "+        }",
        "+",
        "+        Err(RuntimeError::new(",
        "+            last_error",
        "+                .map(|error| error.to_string())",
        "+                .unwrap_or_else(|| String::from("provider chain exhausted with no attempts")),",
        "+        ))",
        "+    }",
        "+}",
        "+",
        "+#[allow(clippy::too_many_lines)]",
        "+async fn stream_with_provider(",
        "+    client: &ProviderClient,",
        "+    message_request: &MessageRequest,",
        "+) -> Result<Vec<AssistantEvent>, ApiError> {",
        "+    let mut stream = client.stream_message(message_request).await?;",
        "+    let mut events = Vec::new();",
        "+    let mut pending_tools: BTreeMap<u32, (String, String, String)> = BTreeMap::new();",
        "+    let mut saw_stop = false;",
        "+",
        "+    while let Some(event) = stream.next_event().await? {",
        "+        match event {",
        "+            ApiStreamEvent::MessageStart(start) => {",
        "+                for block in start.message.content {",
        "+                    push_output_block(block, 0, &mut events, &mut pending_tools, true);",
        "+                }",
        "+            }",
        "+            ApiStreamEvent::ContentBlockStart(start) => {",
        "+                push_output_block(",
        "+                    start.content_block,",
        "+                    start.index,",
        "+                    &mut events,",
        "+                    &mut pending_tools,",
        "+                    true,",
        "+                );",
        "+            }",
        "+            ApiStreamEvent::ContentBlockDelta(delta) => match delta.delta {",
        "+                ContentBlockDelta::TextDelta { text } => {",
        "+                    if !text.is_empty() {",
        "+                        events.push(AssistantEvent::TextDelta(text));",
        "+                    }",
        "+                }",
        "+                ContentBlockDelta::InputJsonDelta { partial_json } => {",
        "+                    if let Some((_, _, input)) = pending_tools.get_mut(&delta.index) {",
        "+                        input.push_str(&partial_json);",
        "+                    }",
        "+                }",
        "+                ContentBlockDelta::ThinkingDelta { .. }",
        "+                | ContentBlockDelta::SignatureDelta { .. } => {}",
        "+            },",
        "+            ApiStreamEvent::ContentBlockStop(stop) => {",
        "+                if let Some((id, name, input)) = pending_tools.remove(&stop.index) {",
        "+                    events.push(AssistantEvent::ToolUse { id, name, input });",
        "+                }",
        "+            }",
        "+            ApiStreamEvent::MessageDelta(delta) => {",
        "+                events.push(AssistantEvent::Usage(delta.usage.token_usage()));",
        "+            }",
        "+            ApiStreamEvent::MessageStop(_) => {",
        "+                saw_stop = true;",
        "+                events.push(AssistantEvent::MessageStop);",
        "+            }",
        "+        }",
        "+    }",
        "+",
        "+    push_prompt_cache_record(client, &mut events);",
        "+",
        "+    if !saw_stop",
        "+        && events.iter().any(|event| {",
        "+            matches!(event, AssistantEvent::TextDelta(text) if !text.is_empty())",
        "+                || matches!(event, AssistantEvent::ToolUse { .. })",
        "+        })",
        "+    {",
        "+        events.push(AssistantEvent::MessageStop);",
        "+    }",
        "+",
        "+    if events",
        "+        .iter()",
        "+        .any(|event| matches!(event, AssistantEvent::MessageStop))",
        "+    {",
        "+        return Ok(events);",
        "+    }",
        "+",
        "+    let response = client",
        "+        .send_message(&MessageRequest {",
        "+            stream: false,",
        "+            ..message_request.clone()",
        "+        })",
        "+        .await?;",
        "+    let mut events = response_to_events(response);",
        "+    push_prompt_cache_record(client, &mut events);",
        "+    Ok(events)",
        "+}",
