        "+fn detect_powershell_shell() -> std::io::Result<&'static str> {",
        "+    if command_exists("pwsh") {",
        "+        Ok("pwsh")",
        "+    } else if command_exists("powershell") {",
        "+        Ok("powershell")",
        "+    } else {",
        "+        Err(std::io::Error::new(",
