        "+fn command_exists(command: &str) -> bool {",
        "+    std::process::Command::new("sh")",
        "+        .arg("-lc")",
        "+        .arg(format!("command -v {command} >/dev/null 2>&1"))",
        "+        .status()",
        "+        .map(|status| status.success())",
        "+        .unwrap_or(false)",
